INSERT INTO temp_counts (premium_count, total_count)
SELECT 
    SUM(CASE WHEN Segment = 'Premium' THEN 1 ELSE 0 END), 
    COUNT(*)
FROM customers
WHERE Country = 'SVK';

SELECT CAST(premium_count AS REAL) * 100 / total_count AS per FROM temp_counts;

DROP TABLE IF EXISTS temp_counts;
